import * as THREE from 'three';
import { createScene } from './data/object.js';
import { writeFileSync, mkdirSync, rmSync } from 'fs';
import { join } from 'path';

const root = createScene();
root.updateMatrixWorld(true);

const OUTPUT = '/root/output';
rmSync(OUTPUT, { recursive: true, force: true });
mkdirSync(join(OUTPUT, 'part_meshes'), { recursive: true });
mkdirSync(join(OUTPUT, 'links'), { recursive: true });

/**
 * Export a BufferGeometry to OBJ format string.
 * @param {THREE.BufferGeometry} geometry
 * @param {THREE.Matrix4|null} matrix - transform to apply to vertices
 * @param {number} vertexOffset - offset for face indices (for merging)
 * @returns {{ objStr: string, vertexCount: number }}
 */
function geometryToOBJ(geometry, matrix, vertexOffset = 0) {
    const pos = geometry.getAttribute('position');
    const idx = geometry.index;
    let out = '';
    const v = new THREE.Vector3();

    // Vertices
    for (let i = 0; i < pos.count; i++) {
        v.set(pos.getX(i), pos.getY(i), pos.getZ(i));
        if (matrix) v.applyMatrix4(matrix);
        out += "'`v ${v.x} ${v.y} ${v.z}'"\\n"'`;
    }

    // Faces
    if (idx) {
        for (let i = 0; i < idx.count; i += 3) {
            const a = idx.getX(i) + 1 + vertexOffset;
            const b = idx.getX(i + 1) + 1 + vertexOffset;
            const c = idx.getX(i + 2) + 1 + vertexOffset;
            out += `f ${a} ${b} ${c}'"\\n"'`;
        }
    } else {
        for (let i = 0; i < pos.count; i += 3) {
            out += `f ${i + 1 + vertexOffset} ${i + 2 + vertexOffset} ${i + 3 + vertexOffset}'"\\n"'`;
        }
    }

    return { objStr: out, vertexCount: pos.count };
}

// Collect parts: Groups (not root) with at least one direct Mesh child
const parts = [];
function collectParts(obj) {
    if (obj.isGroup && obj !== root) {
        const meshChildren = obj.children.filter(c => c.isMesh);
        if (meshChildren.length > 0) {
            parts.push({ name: obj.name, group: obj, meshes: meshChildren });
        }
    }
    for (const child of obj.children) collectParts(child);
}
collectParts(root);

console.log(`Found ${parts.length} parts`);

// Export using world space (mesh.matrixWorld applied to raw geometry)
for (const part of parts) {
    const partDir = join(OUTPUT, '"'part_meshes', part.name);
    mkdirSync(partDir, { recursive: true });

    let linkStr = '';
    let linkOffset = 0;

    for (const mesh of part.meshes) {
        // Individual mesh: world space
        const { objStr, vertexCount } = geometryToOBJ(mesh.geometry, mesh.matrixWorld);
        writeFileSync(join(partDir, "'`${mesh.name}.obj`), objStr);

        // Accumulate for link (combined OBJ with correct face offsets)
        const linkResult = geometryToOBJ(mesh.geometry, mesh.matrixWorld, linkOffset);
        linkStr += linkResult.objStr;
        linkOffset += vertexCount;
    }

    writeFileSync(join(OUTPUT, '"'links', "'`${part.name}.obj`), linkStr);
}

console.log('"'Export complete"'!'"');
parts.forEach(p => console.log("'`  ${p.name}: ${p.meshes.length} meshes`));
EOF
