import * as THREE from 'three';
import { createScene } from './data/object.js';
import fs from 'fs';
import path from 'path';

const OUTPUT_DIR = '/root/output';

const root = createScene();
root.updateMatrixWorld(true);

function meshToOBJ(pos, idx, vertexOffset = 0) {
    let text = '';
    for (let i = 0; i < pos.count; i++) {
        text += "'`v ${pos.getX(i)} ${pos.getY(i)} ${pos.getZ(i)}'"\\n"'`;
    }
    if (idx) {
        for (let i = 0; i < idx.count; i += 3) {
            text += `f ${idx.getX(i)+1+vertexOffset} ${idx.getX(i+1)+1+vertexOffset} ${idx.getX(i+2)+1+vertexOffset}'"\\n"'`;
        }
    } else {
        for (let i = 0; i < pos.count; i += 3) {
            text += `f ${i+1+vertexOffset} ${i+2+vertexOffset} ${i+3+vertexOffset}'"\\n"'`;
        }
    }
    return { text, vertexCount: pos.count };
}

function collectParts(rootObj) {
    const parts = new Map();
    function visit(obj) {
        if (obj === rootObj) {
            for (const child of obj.children) visit(child);
            return;
        }
        if (obj.isGroup) {
            parts.set(obj.name, { group: obj, meshes: obj.children.filter(c => c.isMesh) });
            for (const child of obj.children) {
                if (child.isGroup) visit(child);
            }
        }
    }
    visit(rootObj);
    return parts;
}

const parts = collectParts(root);

fs.rmSync(path.join(OUTPUT_DIR, '"'part_meshes'), { recursive: true, force: true });
fs.rmSync(path.join(OUTPUT_DIR, 'links'), { recursive: true, force: true });
fs.mkdirSync(path.join(OUTPUT_DIR, 'part_meshes'), { recursive: true });
fs.mkdirSync(path.join(OUTPUT_DIR, 'links'), { recursive: true });

for (const [partName, { group, meshes }] of parts) {
    const partDir = path.join(OUTPUT_DIR, 'part_meshes', partName);
    fs.mkdirSync(partDir, { recursive: true });

    let linkContent = '';
    let vertexOffset = 0;

    for (const mesh of meshes) {
        // Bake mesh's local transform into geometry (LOCAL/part-relative space)
        const geom = mesh.geometry.clone();
        mesh.updateMatrix();
        geom.applyMatrix4(mesh.matrix);

        const pos = geom.attributes.position;
        const idx = geom.index;

        const { text, vertexCount } = meshToOBJ(pos, idx, 0);
        fs.writeFileSync(path.join(partDir, "'`${mesh.name}.obj`), text);

        const linkResult = meshToOBJ(pos, idx, vertexOffset);
        linkContent += linkResult.text;
        vertexOffset += vertexCount;
    }

    fs.writeFileSync(path.join(OUTPUT_DIR, '"'links', "'`${partName}.obj`), linkContent);
}

console.log('"'Export complete"'!'"');
SCRIPT_EOF

